# Collect all var_call_ variables from the environment
env = globals()
# Load stockinfo mapping
stockinfo_path = env.get('var_call_HEKveFApzB5OJoibVOo3FeNG')
stock_map = {}
if isinstance(stockinfo_path, str):
    try:
        with open(stockinfo_path, 'r') as f:
            stockinfo = json.load(f)
        for rec in stockinfo:
            sym = rec.get('Symbol')
            desc = rec.get('Company Description')
            if sym:
                stock_map[sym] = desc
    except Exception:
        stockmap = {}

records = []
for name, val in env.items():
    if not name.startswith('var_call_'):
        continue
    # skip stockinfo and trade_tables large files already handled
    if name in ('var_call_HEKveFApzB5OJoibVOo3FeNG', 'var_call_bB4AdaDG75rQ4lJcrmnQ5gCQ'):
        continue
    v = val
    # if string path to json, try load
    if isinstance(v, str):
        try:
            with open(v, 'r') as f:
                v = json.load(f)
        except Exception:
            # not a file path, skip
            continue
    if isinstance(v, list):
        for rec in v:
            if isinstance(rec, dict) and 'symbol' in rec:
                sym = rec.get('symbol')
                up = rec.get('up_days')
                down = rec.get('down_days')
                # convert to numbers if possible
                try:
                    up_n = float(up)
                except Exception:
                    up_n = float('nan')
                try:
                    down_n = float(down)
                except Exception:
                    down_n = float('nan')
                records.append({'symbol': sym, 'up': up_n, 'down': down_n})

# Filter where up > down and not nan
valid = [r for r in records if not math.isnan(r['up']) and not math.isnan(r['down']) and r['up'] > r['down']]
# Sort by up descending
valid_sorted = sorted(valid, key=lambda x: (-x['up'], x['symbol']))
# Take top 5
top5 = valid_sorted[:5]
# Map to company names (Company Description)
result_names = []
for r in top5:
    sym = r['symbol']
    name = stock_map.get(sym) or None
    result_names.append({'symbol': sym, 'company_name': name, 'up_days': int(r['up']), 'down_days': int(r['down'])})

print('__RESULT__:')
print(json.dumps(result_names))"}

